// lib/ollama.ts
// Calls llama3.2 via Ollama's /api/chat and yields the answer token-by-token.
// Used by the chat route to stream a reply to the browser as it's generated.

const OLLAMA_CHAT_URL = "http://localhost:11434/api/chat";
const CHAT_MODEL = "llama3.2";

type ChatMessage = { role: "system" | "user" | "assistant"; content: string };

// An async generator: it produces a sequence of string pieces over time.
// `AsyncGenerator<string>` is the type — "yields strings, asynchronously".
// The caller can `for await (const piece of generate(...))` to consume them.
export async function* generate(messages: ChatMessage[]): AsyncGenerator<string> {
  const res = await fetch(OLLAMA_CHAT_URL, {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify({ model: CHAT_MODEL, messages, stream: true }),
  });

  if (!res.ok || !res.body) {
    throw new Error(`Ollama chat failed: ${res.status} ${res.statusText}`);
  }

  // Ollama streams NDJSON: one JSON object per line. We read the raw bytes,
  // decode to text, and split on newlines. A `buffer` holds any partial line
  // left over between network chunks (a line can be split across reads).
  con

ON object per line. We read the raw bytes,
  // decode to text, and split on newlines. A `buffer` holds any partial line
  // left over between network chunks (a line can be split across reads).
  const reader = res.body.getReader();
  const decoder = new TextDecoder();
  let buffer = "";

  while (true) {
    const { done, value } = await reader.read();
    if (done) break;

    buffer += decoder.decode(value, { stream: true });
    const lines = buffer.split("\n");
    buffer = lines.pop() ?? ""; // last item may be an incomplete line; keep it

    for (const line of lines) {
      if (!line.trim()) continue;
      const json = JSON.parse(line);
      const piece = json.message?.content;
      if (piece) yield piece; // hand this fragment of the answer to the caller
      if (json.done) return;
    }
  }
}

import type { StoredChunk } from "./store";

export type Chunk = {
  text: string;
  source: string;
};

export function chunk(
  text: string,
  source: string,
  maxChars = 1200,
  overlap = 200
): Chunk[] {
  const chunks: Chunk[] = [];
  let start = 0;
  while (start < text.length) {
    const end = Math.min(start + maxChars, text.length);
    chunks.push({ text: text.slice(start, end), source });
    start += maxChars - overlap;
  }
  return chunks;
}

export function cosineSimilarity(a: number[], b: number[]): number {
  let dot = 0;     // running sum of a[i] * b[i]
  let normA = 0;   // running sum of a[i] squared
  let normB = 0;   // running sum of b[i] squared

  for (let i = 0; i < a.length; i++) {
    dot += a[i] * b[i];
    normA += a[i] * a[i];
    normB += b[i] * b[i];
  }

  if (normA === 0 || normB === 0) return 0;  // guard divide-by-zero

  return dot / (Math.sqrt(normA) * Math.sqrt(normB));
}

// Given the question's vector and every stored chunk, return the top-k
// chunks ranked by similarity. This is the retrieval step: it decides
// WHICH pieces of code get fed to the LLM as context.
export function retrieve(
  queryEmbedding: number[],
  store: StoredChunk

// chunks ranked by similarity. This is the retrieval step: it decides
// WHICH pieces of code get fed to the LLM as context.
export function retrieve(
  queryEmbedding: number[],
  store: StoredChunk[],
  k = 4
): { chunk: StoredChunk; score: number }[] {
  return store
    .map((c) => ({ chunk: c, score: cosineSimilarity(queryEmbedding, c.embedding) }))
    .sort((a, b) => b.score - a.score)
    .slice(0, k);
}

// lib/store.ts
// Our "database" — a JSON file holding every chunk plus its vector.
// saveStore(): called once by the ingest script.
// loadStore(): called by the chat backend on each question to search against.

import fs from "node:fs";
import path from "node:path";
import type { Chunk } from "./rag";

// A stored chunk is a Chunk (text + source) PLUS its embedding vector.
// `&` is a TS intersection: "a StoredChunk has everything a Chunk has,
// and additionally an embedding field." This is the exact record we search.
export type StoredChunk = Chunk & {
  embedding: number[];
};

const STORE_PATH = path.join(process.cwd(), "data", "index.json");

export function saveStore(store: StoredChunk[]): void {
  fs.writeFileSync(STORE_PATH, JSON.stringify(store), "utf-8");
}

export function loadStore(): StoredChunk[] {
  if (!fs.existsSync(STORE_PATH)) {
    throw new Error("No index found. Run the ingest script first.");
  }
  return JSON.parse(fs.readFileSync(STORE_PATH, "utf-8")) as StoredChunk[];
}

